buggy_code:
public void close() throws IOException {
    if (!this.closed) {
        super.close();
        this.closed = true;
    }
}

fix_code:
public void close() throws IOException {
    if (!this.closed) {
        this.finish();
        super.close();
        this.closed = true;
    }
}

